import { Router } from 'express';
import { ProjectController } from '../controllers/ProjectController.js';
import { validate } from '../middleware/validate.js';
import { ProjectCreateSchema, ProjectUpdateSchema } from '../helpers/validation.js';
import { requireAuth, checkPermission } from '../middleware/auth.js';
const router = Router();
const controller = new ProjectController();
router.use(requireAuth);
router.post('/', checkPermission('project:create'), validate(ProjectCreateSchema), controller.create);
router.get('/', checkPermission('project:view'), controller.getAll);
router.get('/:id', checkPermission('project:view'), controller.getById);
router.put('/:id', checkPermission('project:create'), validate(ProjectUpdateSchema), controller.update);
router.delete('/:id', checkPermission('project:delete'), controller.delete);
router.post('/:id/members', checkPermission('project:create'), controller.addMember);
export default router;
